// ─── helpers ───────────────────────────────────────────────
function pct(a, b) {
  if (!b || b === 0) return 'n/a';
  return ((a - b) / b * 100).toFixed(1) + '%';
}
function diff(a, b) {
  if (a == null || b == null) return 'n/a';
  const d = a - b;
  return (d >= 0 ? '+' : '') + d.toLocaleString();
}
function parseDate(d) {
  // handles "2024-01", "2024-01-01", "01/2024", "Jan 2024", numeric year+month
  if (!d) return null;
  const s = String(d).trim();
  const m1 = s.match(/^(\d{4})[\-\/](\d{1,2})/);
  if (m1) return { year: +m1[1], month: +m1[2] };
  const m2 = s.match(/^(\d{1,2})[\-\/](\d{4})/);
  if (m2) return { year: +m2[2], month: +m2[1] };
  return null;
}
function dateKey(year, month) { return year * 100 + month; }

// ─── collect items ──────────────────────────────────────────
const all = $input.all().map(i => i.json);

// detect sheet by fields present
const bySheet = { demand_global: [], demand_transaction: [], demand_asset: [],
  demand_departement: [], ranking_global_war: [], audience: [] };

for (const row of all) {
  const keys = Object.keys(row).map(k => k.toLowerCase());
  if (keys.includes('rank_organic_war') || keys.includes('url_hostname')) {
    bySheet.ranking_global_war.push(row);
  } else if (keys.some(k => k.includes('segment.transaction') || k === 'segment')) {
    bySheet.demand_transaction.push(row);
  } else if (keys.some(k => k.includes('segment.asset') || k.includes('asset'))) {
    bySheet.demand_asset.push(row);
  } else if (keys.some(k => k.includes('departement') || k.includes('département'))) {
    bySheet.demand_departement.push(row);
  } else if (keys.some(k => k.includes('brand') || k.includes('nonbrand') || k.includes('anonymous') || k === 'type')) {
    bySheet.audience.push(row);
  } else if (keys.includes('volume') && (keys.includes('month') || keys.includes('year') || keys.some(k => k.includes('date')))) {
    bySheet.demand_global.push(row);
  }
}

let report = '';

// ─── 1. demand_global ───────────────────────────────────────
{
  const rows = bySheet.demand_global;
  // sort by date
  rows.sort((a, b) => {
    const ka = a.year ? dateKey(+a.year, +a.month) : (parseDate(a.date || a['date (Année Mois)'])?.year * 100 + parseDate(a.date || a['date (Année Mois)'])?.month || 0);
    const kb = b.year ? dateKey(+b.year, +b.month) : (parseDate(b.date || b['date (Année Mois)'])?.year * 100 + parseDate(b.date || b['date (Année Mois)'])?.month || 0);
    return ka - kb;
  });
  const n = rows.length;
  if (n >= 2) {
    const cur = rows[n-1]; const prev = rows[n-2];
    const yoy = rows.find(r => {
      const k1 = cur.year ? dateKey(+cur.year - 1, +cur.month) : null;
      if (!k1) return false;
      return r.year ? dateKey(+r.year, +r.month) === k1 : false;
    });
    report += `## 1. demand_global\n`;
    report += `- Current month: ${cur.volume?.toLocaleString() || cur.volume}\n`;
    report += `- vs M-1: ${diff(+cur.volume, +prev.volume)} (${pct(+cur.volume, +prev.volume)})\n`;
    if (yoy) report += `- vs same month last year: ${diff(+cur.volume, +yoy.volume)} (${pct(+cur.volume, +yoy.volume)})\n`;
    // 12-month trend
    const last12 = rows.slice(-13);
    let ups = 0, downs = 0;
    for (let i = 1; i < last12.length; i++) {
      if (+last12[i].volume > +last12[i-1].volume) ups++; else downs++;
    }
    report += `- 12-month trend: ${ups} months up, ${downs} months down → ${ups > downs ? 'INCREASING' : 'DECREASING'}\n`;
  } else {
    report += `## 1. demand_global\n- Not enough data (${n} rows)\n`;
  }
  report += '\n';
}

// ─── 2. demand_transaction ──────────────────────────────────
{
  const rows = bySheet.demand_transaction;
  const segKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('segment')) || 'segment.transaction';
  const dateK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('date')) || 'date';
  // group by segment
  const segments = {};
  for (const r of rows) {
    const seg = r[segKey] || 'unknown';
    if (!segments[seg]) segments[seg] = [];
    segments[seg].push(r);
  }
  report += `## 2. demand_transaction\n`;
  for (const [seg, srows] of Object.entries(segments)) {
    srows.sort((a, b) => String(a[dateK]).localeCompare(String(b[dateK])));
    const n = srows.length;
    if (n >= 2) {
      const cur = +srows[n-1].volume; const prev = +srows[n-2].volume;
      report += `- ${seg}: ${cur.toLocaleString()} | vs M-1: ${diff(cur, prev)} (${pct(cur, prev)})\n`;
    }
  }
  report += '\n';
}

// ─── 3. demand_asset ────────────────────────────────────────
{
  const rows = bySheet.demand_asset;
  const segKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('asset') || k.toLowerCase().includes('segment')) || 'segment.asset';
  const dateK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('date')) || 'date';
  const assets = {};
  for (const r of rows) {
    const seg = r[segKey] || 'unknown';
    if (!assets[seg]) assets[seg] = [];
    assets[seg].push(r);
  }
  report += `## 4. demand_asset\n`;
  for (const [seg, srows] of Object.entries(assets)) {
    srows.sort((a, b) => String(a[dateK]).localeCompare(String(b[dateK])));
    const n = srows.length;
    if (n >= 2) {
      const cur = +srows[n-1].volume; const prev = +srows[n-2].volume;
      report += `- ${seg}: ${cur.toLocaleString()} | vs M-1: ${diff(cur, prev)} (${pct(cur, prev)})\n`;
    }
  }
  report += '\n';
}

// ─── 4. demand_departement ──────────────────────────────────
{
  const rows = bySheet.demand_departement;
  const deptKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('dept') || k.toLowerCase().includes('departement') || k.toLowerCase().includes('département')) || 'departement';
  const dateK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('date')) || 'date';
  // get last available date
  const dates = [...new Set(rows.map(r => String(r[dateK])))].sort();
  const lastDate = dates[dates.length - 1];
  const prevDate = dates[dates.length - 2];
  const prev2Date = dates[dates.length - 3];
  // volumes for last month per dept
  const lastRows = rows.filter(r => String(r[dateK]) === lastDate);
  lastRows.sort((a, b) => +b.volume - +a.volume);
  const top10 = lastRows.slice(0, 10);
  report += `## 5. demand_departement (top 10, ${lastDate})\n`;
  for (const r of top10) {
    const dept = r[deptKey];
    const v = +r.volume;
    const p = rows.find(x => String(x[dateK]) === prevDate && x[deptKey] === dept);
    const p2 = rows.find(x => String(x[dateK]) === prev2Date && x[deptKey] === dept);
    const t = p ? pct(v, +p.volume) : 'n/a';
    const t2 = p2 ? pct(+p?.volume, +p2.volume) : 'n/a';
    report += `- ${dept}: ${v.toLocaleString()} | M-1: ${t} | M-2: ${t2}\n`;
  }
  report += '\n';
}

// ─── 5. ranking_global_war ──────────────────────────────────
{
  const rows = bySheet.ranking_global_war;
  const dateK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('date')) || 'date';
  const hostK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('host') || k.toLowerCase().includes('url')) || 'url_hostname';
  const rankK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('war') || k.toLowerCase().includes('rank')) || 'rank_organic_war';
  const dates = [...new Set(rows.map(r => String(r[dateK])))].sort();
  const lastDate = dates[dates.length - 1];
  const prevDate = dates[dates.length - 2];
  const lastRows = rows.filter(r => String(r[dateK]) === lastDate);
  lastRows.sort((a, b) => +b[rankK] - +a[rankK]);
  report += `## 3. ranking_global_war (${lastDate})\n`;
  for (const r of lastRows.slice(0, 10)) {
    const host = r[hostK];
    const score = +r[rankK];
    const prev = rows.find(x => String(x[dateK]) === prevDate && x[hostK] === host);
    const prevScore = prev ? +prev[rankK] : null;
    const evol = prevScore ? ` | vs prev: ${diff(score, prevScore)} (${pct(score, prevScore)})` : '';
    const isSeloger = host && host.toLowerCase().includes('seloger') ? ' ← SeLoger Neuf' : '';
    report += `- ${host}: WAR ${score.toLocaleString()}${evol}${isSeloger}\n`;
  }
  report += '\n';
}

// ─── 6. audience ────────────────────────────────────────────
{
  const rows = bySheet.audience;
  const dateK = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('date')) || 'date';
  const typeK = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'type' || k.toLowerCase().includes('brand')) || 'type';
  const dates = [...new Set(rows.map(r => String(r[dateK])))].sort();
  const lastDate = dates[dates.length - 1];
  const prevDate = dates[dates.length - 2];
  const cur = rows.filter(r => String(r[dateK]) === lastDate);
  const prev = rows.filter(r => String(r[dateK]) === prevDate);
  const totalCur = cur.reduce((s, r) => s + (+r.clicks || +r.volume || 0), 0);
  const totalPrev = prev.reduce((s, r) => s + (+r.clicks || +r.volume || 0), 0);
  report += `## 6. audience (${lastDate})\n`;
  for (const r of cur) {
    const type = r[typeK] || 'unknown';
    const v = +r.clicks || +r.volume || 0;
    const share = totalCur ? (v / totalCur * 100).toFixed(1) + '%' : 'n/a';
    const p = prev.find(x => (x[typeK] || 'unknown') === type);
    const evol = p ? pct(v, +p.clicks || +p.volume || 0) : 'n/a';
    report += `- ${type}: ${v.toLocaleString()} (${share}) | vs prev: ${evol}\n`;
  }
  report += '\n';
}

return [{ json: { report } }];
